# Code

```javascript
(function () {
  return {
    meta: {
      name: 'ExamplePlugin',
      version: '1.0.1',
      platform: '0.26.0',
      author: 'Marc Cawood',
      description: 'Demo plugin: shows the {meta, init, start} contract by registering a macro.',
      url: 'https://cawoodm.github.io/twikki',
    },
    init() {
      // Register a macro at init time, after all plugins are loaded.
      tw.extensions.registerMacro('example', 'hello', name => `Hello ${name}`, {
        version: '1.0.0',
      });
    },
    start() {
      // Optional. Empty for this demo — the macro is the only side effect.
    },
  };
})();
```

